import { sqliteTable, text, integer, index } from 'drizzle-orm/sqlite-core';
import { sql } from 'drizzle-orm';

// ── Status enums (stored as text in SQLite, validated by Zod at app layer) ──

export const milestoneStatusEnum = ['draft', 'in-progress', 'completed', 'archived'] as const;
export type MilestoneStatus = (typeof milestoneStatusEnum)[number];

export const moduleStatusEnum = ['draft', 'in-progress', 'completed'] as const;
export type ModuleStatus = (typeof moduleStatusEnum)[number];

export const taskStatusEnum = [
	'todo',
	'in-progress',
	'blocked',
	'review',
	'done',
	'skipped'
] as const;
export type TaskStatus = (typeof taskStatusEnum)[number];

// ── Milestone ────────────────────────────────────────────────────────────────
// Primary entity. ID format: MS-{seq} (e.g. MS-1, MS-2).

export const milestones = sqliteTable(
	'milestones',
	{
		id: text('id').primaryKey(), // MS-{seq}
		title: text('title').notNull(),
		sourceMd: text('source_md'),
		gitUrl: text('git_url'),
		status: text('status', { enum: milestoneStatusEnum }).notNull().default('draft'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`)
	},
	(table) => [index('milestone_status_idx').on(table.status)]
);

// ── Module ───────────────────────────────────────────────────────────────────
// Groups tasks within a milestone. ID format: MOD-{milestone_seq}-{seq}.

export const modules = sqliteTable(
	'modules',
	{
		id: text('id').primaryKey(), // MOD-{ms_seq}-{seq}
		milestoneId: text('milestone_id')
			.notNull()
			.references(() => milestones.id, { onDelete: 'cascade' }),
		name: text('name').notNull(),
		description: text('description'),
		status: text('status', { enum: moduleStatusEnum }).notNull().default('draft'),
		sortOrder: integer('sort_order').notNull().default(0)
	},
	(table) => [
		index('module_milestone_id_idx').on(table.milestoneId),
		index('module_status_idx').on(table.status)
	]
);

// ── Task ─────────────────────────────────────────────────────────────────────
// Atomic unit of work. ID format: TASK-{global_seq}.
// short_id is a global auto-increment for human-friendly references.

export const tasks = sqliteTable(
	'tasks',
	{
		id: text('id').primaryKey(), // TASK-{global_seq}
		shortId: integer('short_id').notNull().unique(), // global auto-increment
		moduleId: text('module_id')
			.notNull()
			.references(() => modules.id, { onDelete: 'cascade' }),
		title: text('title').notNull(),
		description: text('description'),
		references: text('references'), // JSON or text blob
		status: text('status', { enum: taskStatusEnum }).notNull().default('todo'),
		assignee: text('assignee'),
		subTotal: integer('sub_total').notNull().default(0),
		subDone: integer('sub_done').notNull().default(0),
		progressMessage: text('progress_message'),
		commitHash: text('commit_hash'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		updatedAt: integer('updated_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		reportedAt: integer('reported_at', { mode: 'timestamp' })
	},
	(table) => [
		index('task_status_module_idx').on(table.status, table.moduleId),
		index('task_status_reported_idx').on(table.status, table.reportedAt),
		index('task_module_id_idx').on(table.moduleId),
		index('task_short_id_idx').on(table.shortId)
	]
);

// ── Type exports for use in application code ──

export type Milestone = typeof milestones.$inferSelect;
export type NewMilestone = typeof milestones.$inferInsert;
export type Module = typeof modules.$inferSelect;
export type NewModule = typeof modules.$inferInsert;
export type Task = typeof tasks.$inferSelect;
export type NewTask = typeof tasks.$inferInsert;

import Database from 'better-sqlite3';
import { drizzle } from 'drizzle-orm/better-sqlite3';
import path from 'node:path';
import fs from 'node:fs';

const dbPath = process.env.DATABASE_PATH || path.join(process.cwd(), 'data', 'tracker.db');

// Ensure data directory exists
const dir = path.dirname(dbPath);
if (!fs.existsSync(dir)) {
	fs.mkdirSync(dir, { recursive: true });
}

const sqlite = new Database(dbPath);

// Enable WAL mode for concurrent read/write support
sqlite.pragma('journal_mode = WAL');
// Enable foreign key enforcement
sqlite.pragma('foreign_keys = ON');

export const db = drizzle(sqlite);
export default db;

export { createMilestoneSchema, updateMilestoneSchema, milestoneResponseSchema } from './milestone.js';
export type { CreateMilestoneInput, UpdateMilestoneInput, MilestoneResponse } from './milestone.js';

export { createModuleSchema, updateModuleSchema, moduleResponseSchema } from './module.js';
export type { CreateModuleInput, UpdateModuleInput, ModuleResponse } from './module.js';

export {
	claimTaskSchema,
	progressTaskSchema,
	completeTaskSchema,
	adminTaskActionSchema,
	taskResponseSchema,
	isValidTransition
} from './task.js';
export type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput,
	TaskResponse
} from './task.js';

export { loginRequestSchema, loginResponseSchema } from './auth.js';
export type { LoginRequest, LoginResponse } from './auth.js';

export {
	decomposeModuleSchema,
	decomposeTaskSchema
} from './decompose.js';
export type {
	DecomposeModule,
	DecomposeTask,
	DecomposeEvent,
	DecomposeModuleEvent,
	DecomposeErrorEvent,
	DecomposeDoneEvent
} from './decompose.js';

export {
	paginationQuerySchema,
	paginatedResponseSchema,
	errorResponseSchema,
	fieldErrorSchema,
	milestoneIdSchema,
	moduleIdSchema,
	taskIdSchema,
	sourceMdSchema,
	SOURCE_MD_MAX_BYTES
} from './common.js';
export type {
	PaginationQuery,
	ErrorResponse,
	FieldError
} from './common.js';

import { z } from 'zod';

// ── LLM output schemas ──────────────────────────────────────────────────────

/** A single task inside a decomposed module. */
export const decomposeTaskSchema = z.object({
	title: z.string().min(1, 'Task title is required').max(500, 'Task title too long'),
	description: z.string().max(5000).optional()
});
export type DecomposeTask = z.infer<typeof decomposeTaskSchema>;

/** A single decomposed module produced by the LLM. */
export const decomposeModuleSchema = z.object({
	name: z.string().min(1, 'Module name is required').max(200, 'Module name too long'),
	description: z.string().max(5000).optional(),
	tasks: z.array(decomposeTaskSchema).min(0)
});
export type DecomposeModule = z.infer<typeof decomposeModuleSchema>;

// ── SSE event types ─────────────────────────────────────────────────────────

/** Union discriminator for SSE events sent to the frontend. */
export type DecomposeEvent = DecomposeModuleEvent | DecomposeErrorEvent | DecomposeDoneEvent;

/** A successfully parsed and validated module chunk. */
export interface DecomposeModuleEvent {
	type: 'module';
	index: number;
	module: DecomposeModule;
}

/** An error occurred during the decompose stream. */
export interface DecomposeErrorEvent {
	type: 'error';
	stage: 'connecting' | 'streaming' | 'parsing';
	message: string;
}

/** Signal that the stream is complete. */
export interface DecomposeDoneEvent {
	type: 'done';
	total: number;
	errors: number;
}

import { z } from 'zod';

// ── Pagination ──────────────────────────────────────────────────────────────

export const paginationQuerySchema = z.object({
	page: z.coerce.number().int().positive().default(1),
	perPage: z.coerce.number().int().positive().max(100).default(20)
});
export type PaginationQuery = z.infer<typeof paginationQuerySchema>;

export const paginatedResponseSchema = <T extends z.ZodTypeAny>(itemSchema: T) =>
	z.object({
		data: z.array(itemSchema),
		pagination: z.object({
			page: z.number().int().positive(),
			perPage: z.number().int().positive(),
			total: z.number().int().nonnegative(),
			totalPages: z.number().int().nonnegative()
		})
	});

// ── Error response ──────────────────────────────────────────────────────────

export const fieldErrorSchema = z.object({
	field: z.string(),
	message: z.string()
});
export type FieldError = z.infer<typeof fieldErrorSchema>;

export const errorResponseSchema = z.object({
	error: z.object({
		code: z.string(),
		message: z.string(),
		details: z.array(fieldErrorSchema).optional()
	})
});
export type ErrorResponse = z.infer<typeof errorResponseSchema>;

// ── ID formats ──────────────────────────────────────────────────────────────

export const milestoneIdSchema = z.string().regex(/^MS-\d+$/, 'Must match MS-{seq}');
export const moduleIdSchema = z.string().regex(/^MOD-\d+-\d+$/, 'Must match MOD-{ms_seq}-{seq}');
export const taskIdSchema = z.string().regex(/^TASK-\d+$/, 'Must match TASK-{seq}');

// ── Source markdown size limit (1 MB) ───────────────────────────────────────

export const SOURCE_MD_MAX_BYTES = 1_048_576;
export const sourceMdSchema = z
	.string()
	.max(SOURCE_MD_MAX_BYTES, `source_md must be under ${SOURCE_MD_MAX_BYTES} bytes`);

import { z } from 'zod';
import { moduleStatusEnum } from '../db/schema.js';
import { moduleIdSchema, milestoneIdSchema } from './common.js';

// ── Create ──────────────────────────────────────────────────────────────────

export const createModuleSchema = z.object({
	milestoneId: milestoneIdSchema,
	name: z.string().min(1, 'Name is required').max(200, 'Name must be under 200 characters'),
	description: z.string().max(5000).optional(),
	sortOrder: z.number().int().nonnegative().default(0)
});
export type CreateModuleInput = z.infer<typeof createModuleSchema>;

// ── Update ──────────────────────────────────────────────────────────────────

export const updateModuleSchema = z.object({
	name: z.string().min(1).max(200).optional(),
	description: z.string().max(5000).optional(),
	status: z.enum(moduleStatusEnum).optional(),
	sortOrder: z.number().int().nonnegative().optional()
});
export type UpdateModuleInput = z.infer<typeof updateModuleSchema>;

// ── Response ────────────────────────────────────────────────────────────────

export const moduleResponseSchema = z.object({
	id: moduleIdSchema,
	milestoneId: milestoneIdSchema,
	name: z.string(),
	description: z.string().nullable(),
	status: z.enum(moduleStatusEnum),
	sortOrder: z.number().int()
});
export type ModuleResponse = z.infer<typeof moduleResponseSchema>;

import { z } from 'zod';
import { taskStatusEnum } from '../db/schema.js';
import { taskIdSchema, moduleIdSchema } from './common.js';

// ── Status transition map ───────────────────────────────────────────────────

const validTransitions: Record<string, string[]> = {
	todo: ['in-progress', 'skipped'],
	'in-progress': ['blocked', 'review', 'todo'],
	blocked: ['in-progress', 'todo'],
	review: ['done', 'in-progress'],
	done: [],
	skipped: []
};

export function isValidTransition(from: string, to: string): boolean {
	return validTransitions[from]?.includes(to) ?? false;
}

// ── Claim ───────────────────────────────────────────────────────────────────

export const claimTaskSchema = z.object({
	assignee: z.string().min(1, 'Assignee is required').max(100)
});
export type ClaimTaskInput = z.infer<typeof claimTaskSchema>;

// ── Progress update ─────────────────────────────────────────────────────────

export const progressTaskSchema = z.object({
	progressMessage: z.string().max(5000).optional(),
	subTotal: z.number().int().nonnegative().optional(),
	subDone: z.number().int().nonnegative().optional()
}).refine(
	(data) => {
		if (data.subTotal !== undefined && data.subDone !== undefined) {
			return data.subDone <= data.subTotal;
		}
		return true;
	},
	{ message: 'sub_done cannot exceed sub_total', path: ['subDone'] }
);
export type ProgressTaskInput = z.infer<typeof progressTaskSchema>;

// ── Complete ────────────────────────────────────────────────────────────────

export const completeTaskSchema = z.object({
	commitHash: z.string().max(40).optional(),
	progressMessage: z.string().max(5000).optional()
});
export type CompleteTaskInput = z.infer<typeof completeTaskSchema>;

// ── Admin action ────────────────────────────────────────────────────────────

export const adminTaskActionSchema = z.object({
	status: z.enum(taskStatusEnum),
	progressMessage: z.string().max(5000).optional()
});
export type AdminTaskActionInput = z.infer<typeof adminTaskActionSchema>;

// ── Response (with resolved references) ─────────────────────────────────────

export const taskResponseSchema = z.object({
	id: taskIdSchema,
	shortId: z.number().int().positive(),
	moduleId: moduleIdSchema,
	title: z.string(),
	description: z.string().nullable(),
	references: z.string().nullable(),
	status: z.enum(taskStatusEnum),
	assignee: z.string().nullable(),
	subTotal: z.number().int().nonnegative(),
	subDone: z.number().int().nonnegative(),
	progressMessage: z.string().nullable(),
	commitHash: z.string().nullable(),
	createdAt: z.string().datetime(),
	updatedAt: z.string().datetime(),
	reportedAt: z.string().datetime().nullable()
});
export type TaskResponse = z.infer<typeof taskResponseSchema>;

import { eq, asc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, milestones } from '$lib/db/schema.js';
import type { CreateModuleInput, UpdateModuleInput } from '$lib/schemas/index.js';

/** Body data for createModule (milestoneId comes from URL param). */
type CreateModuleBody = Omit<CreateModuleInput, 'milestoneId'>;

// ── ID Generation ────────────────────────────────────────────────────────────

/** Generate MOD-{milestone_seq}-{next_seq} ID. */
export async function nextModuleId(
	db: BetterSQLite3Database<any>,
	milestoneId: string
): Promise<string> {
	const msSeq = milestoneId.replace('MS-', '');
	const rows = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();
	let maxSeq = 0;
	for (const row of rows) {
		// Format: MOD-{msSeq}-{seq}
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MOD-${msSeq}-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createModule(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	data: CreateModuleBody
) {
	// Verify milestone exists
	const ms = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!ms) return null;

	const id = await nextModuleId(db, milestoneId);
	const result = await db
		.insert(modules)
		.values({
			id,
			milestoneId,
			name: data.name,
			description: data.description ?? null,
			sortOrder: data.sortOrder ?? 0
		})
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── List by Milestone ────────────────────────────────────────────────────────

export async function listModulesByMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string
) {
	const rows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();
	return rows.map(formatModuleResponse);
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateModule(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateModuleInput
) {
	const existing = await db.select().from(modules).where(eq(modules.id, id)).get();
	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.name !== undefined) updates.name = data.name;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.status !== undefined) updates.status = data.status;
	if (data.sortOrder !== undefined) updates.sortOrder = data.sortOrder;

	if (Object.keys(updates).length === 0) {
		return formatModuleResponse(existing);
	}

	const result = await db
		.update(modules)
		.set(updates)
		.where(eq(modules.id, id))
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

import { eq, asc, sql, and, inArray } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { tasks, modules, milestones } from '$lib/db/schema.js';
import type { TaskStatus } from '$lib/db/schema.js';
import type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput
} from '$lib/schemas/index.js';
import { isValidTransition } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next TASK-{global_seq} ID and short_id. */
export async function nextTaskId(db: BetterSQLite3Database<any>): Promise<{ id: string; shortId: number }> {
	const rows = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxSeq = 0;
	let maxShort = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
		if (row.shortId > maxShort) maxShort = row.shortId;
	}
	return { id: `TASK-${maxSeq + 1}`, shortId: maxShort + 1 };
}

// ── List (with filters) ─────────────────────────────────────────────────────

export interface TaskFilters {
	status?: string;
	milestoneId?: string;
	moduleId?: string;
}

export async function listTasks(
	db: BetterSQLite3Database<any>,
	filters: TaskFilters = {}
) {
	const conditions = [];
	if (filters.status) conditions.push(eq(tasks.status, filters.status as TaskStatus));
	if (filters.moduleId) conditions.push(eq(tasks.moduleId, filters.moduleId));

	// If milestoneId, join through modules
	if (filters.milestoneId) {
		const modRows = await db
			.select({ id: modules.id })
			.from(modules)
			.where(eq(modules.milestoneId, filters.milestoneId))
			.all();
		const modIds = modRows.map((m) => m.id);
		if (modIds.length === 0) return [];
		conditions.push(inArray(tasks.moduleId, modIds));
	}

	const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
	const rows = await db
		.select()
		.from(tasks)
		.where(whereClause)
		.orderBy(asc(tasks.shortId))
		.all();
	return rows.map(formatTaskResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getTask(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const row = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!row) return null;

	// Resolve module and milestone info
	const mod = await db.select().from(modules).where(eq(modules.id, row.moduleId)).get();
	const milestone = mod
		? await db.select().from(milestones).where(eq(milestones.id, mod.milestoneId)).get()
		: null;

	return {
		...formatTaskResponse(row),
		module: mod
			? {
					id: mod.id,
					milestoneId: mod.milestoneId,
					name: mod.name,
					status: mod.status
				}
			: null,
		milestone: milestone
			? {
					id: milestone.id,
					title: milestone.title,
					status: milestone.status
				}
			: null
	};
}

// ── Claim (optimistic lock) ──────────────────────────────────────────────────

export async function claimTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ClaimTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Only allow claiming if task is todo or in-progress
	if (existing.status !== 'todo' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	// Optimistic lock: if already assigned to someone else, reject
	if (existing.assignee && existing.assignee !== data.assignee) {
		return {
			error: 'conflict' as const,
			currentAssignee: existing.assignee,
			task: formatTaskResponse(existing)
		};
	}

	// Transition status if needed
	const statusUpdate =
		existing.status === 'todo' ? 'in-progress' : undefined;

	const updates: Record<string, any> = { assignee: data.assignee };
	if (statusUpdate) updates.status = statusUpdate;
	updates.updatedAt = sql`(unixepoch())`;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Progress ─────────────────────────────────────────────────────────────────

export async function progressTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ProgressTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	if (existing.status !== 'in-progress' && existing.status !== 'todo' && existing.status !== 'blocked') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;
	if (data.subTotal !== undefined) updates.subTotal = data.subTotal;
	if (data.subDone !== undefined) updates.subDone = data.subDone;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Complete ─────────────────────────────────────────────────────────────────

export async function completeTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: CompleteTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Must be in review or in-progress to complete
	if (existing.status !== 'review' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = {
		status: 'done',
		updatedAt: sql`(unixepoch())`,
		reportedAt: sql`(unixepoch())`
	};
	if (data.commitHash !== undefined) updates.commitHash = data.commitHash ?? null;
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Admin Action ─────────────────────────────────────────────────────────────

export type AdminActionError = {
	error: 'not_found' | 'invalid_transition' | 'invalid_status';
	detail?: string;
};

export async function adminTaskAction(
	db: BetterSQLite3Database<any>,
	id: string,
	data: AdminTaskActionInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Admin can force any status, but validate transition for non-force actions
	// For admin actions, we allow any status change (admin override)
	const updates: Record<string, any> = {
		status: data.status,
		updatedAt: sql`(unixepoch())`
	};

	// If setting to done, also set reportedAt
	if (data.status === 'done' && !existing.reportedAt) {
		updates.reportedAt = sql`(unixepoch())`;
	}
	// If reopening from done, clear reportedAt
	if (data.status !== 'done' && existing.reportedAt) {
		updates.reportedAt = null;
	}

	if (data.progressMessage !== undefined) {
		updates.progressMessage = data.progressMessage ?? null;
	}

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

import { eq, desc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { milestones, modules, tasks } from '$lib/db/schema.js';
import type { CreateMilestoneInput, UpdateMilestoneInput } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next MS-{seq} ID by querying max existing seq. */
export async function nextMilestoneId(db: BetterSQLite3Database<any>): Promise<string> {
	const rows = await db.select({ id: milestones.id }).from(milestones).all();
	let maxSeq = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('MS-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MS-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createMilestone(
	db: BetterSQLite3Database<any>,
	data: CreateMilestoneInput
) {
	const id = await nextMilestoneId(db);
	const result = await db
		.insert(milestones)
		.values({
			id,
			title: data.title,
			sourceMd: data.sourceMd ?? null,
			gitUrl: data.gitUrl && data.gitUrl !== '' ? data.gitUrl : null
		})
		.returning()
		.get();
	return formatMilestoneResponse(result);
}

// ── List ─────────────────────────────────────────────────────────────────────

export async function listMilestones(db: BetterSQLite3Database<any>) {
	const rows = await db.select().from(milestones).orderBy(desc(milestones.createdAt), desc(milestones.id)).all();
	return rows.map(formatMilestoneResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getMilestone(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const milestone = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!milestone) return null;

	// Fetch modules for this milestone
	const modRows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, id))
		.all();

	// Fetch tasks for each module
	const modulesWithTasks = await Promise.all(
		modRows.map(async (mod) => {
			const taskRows = await db
				.select()
				.from(tasks)
				.where(eq(tasks.moduleId, mod.id))
				.all();
			return {
				...formatModuleResponse(mod),
				tasks: taskRows.map(formatTaskResponse)
			};
		})
	);

	return {
		...formatMilestoneResponse(milestone),
		modules: modulesWithTasks
	};
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateMilestone(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateMilestoneInput
) {
	const existing = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.title !== undefined) updates.title = data.title;
	if (data.sourceMd !== undefined) updates.sourceMd = data.sourceMd ?? null;
	if (data.gitUrl !== undefined) updates.gitUrl = data.gitUrl === '' ? null : data.gitUrl;
	if (data.status !== undefined) updates.status = data.status;

	if (Object.keys(updates).length === 0) {
		return formatMilestoneResponse(existing);
	}

	const result = await db
		.update(milestones)
		.set(updates)
		.where(eq(milestones.id, id))
		.returning()
		.get();

	return formatMilestoneResponse(result);
}

// ── Formatters ───────────────────────────────────────────────────────────────

function formatMilestoneResponse(row: any) {
	return {
		id: row.id,
		title: row.title,
		sourceMd: row.sourceMd,
		gitUrl: row.gitUrl,
		status: row.status,
		createdAt: new Date(row.createdAt).toISOString()
	};
}

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

export { formatModuleResponse, formatTaskResponse };

/**
 * Minimal OpenAI-compatible streaming LLM client.
 * Uses raw `fetch` + `ReadableStream` — no external dependencies.
 *
 * Reads LLM_API_KEY, LLM_MODEL, LLM_BASE_URL from environment.
 * LLM_API_KEY is never logged or included in SSE responses.
 */

const DEFAULT_BASE_URL = 'https://api.openai.com/v1';
const DEFAULT_MODEL = 'gpt-4o-mini';
const TIMEOUT_MS = 30_000;

export class LlmClient {
	private readonly apiKey: string;
	private readonly model: string;
	private readonly baseUrl: string;
	private readonly timeoutMs: number;

	constructor(opts?: { baseUrl?: string; model?: string; apiKey?: string; timeoutMs?: number }) {
		this.apiKey = opts?.apiKey ?? process.env.LLM_API_KEY ?? '';
		this.model = opts?.model ?? process.env.LLM_MODEL ?? DEFAULT_MODEL;
		this.baseUrl = (opts?.baseUrl ?? process.env.LLM_BASE_URL ?? DEFAULT_BASE_URL).replace(/\/+$/, '');
		this.timeoutMs = opts?.timeoutMs ?? TIMEOUT_MS;
	}

	/**
	 * Stream a chat-completion and yield content deltas as strings.
	 * Parses SSE `data:` lines from the OpenAI-compatible response.
	 *
	 * Throws on non-OK HTTP status, timeout, or stream errors.
	 */
	async *chatCompletionStream(systemPrompt: string, userMessage: string): AsyncGenerator<string> {
		const url = `${this.baseUrl}/chat/completions`;

		console.info('[llm-client] Request:', {
			url,
			model: this.model,
			systemPromptLength: systemPrompt.length,
			userMessageLength: userMessage.length
			// apiKey intentionally omitted
		});

		const controller = new AbortController();
		const timer = setTimeout(() => controller.abort(), this.timeoutMs);

		let response: Response;
		try {
			response = await fetch(url, {
				method: 'POST',
				headers: {
					'Content-Type': 'application/json',
					Authorization: `Bearer ${this.apiKey}`
				},
				body: JSON.stringify({
					model: this.model,
					stream: true,
					messages: [
						{ role: 'system', content: systemPrompt },
						{ role: 'user', content: userMessage }
					]
				}),
				signal: controller.signal
			});
		} catch (err: any) {
			clearTimeout(timer);
			if (err.name === 'AbortError') {
				throw new Error(`LLM request timed out after ${this.timeoutMs}ms`);
			}
			throw new Error(`LLM connection failed: ${err.message}`);
		}

		clearTimeout(timer);

		if (!response.ok) {
			const body = await response.text().catch(() => '<unreadable>');
			throw new Error(`LLM API returned ${response.status}: ${body.slice(0, 500)}`);
		}

		// ── Parse SSE stream ────────────────────────────────────────────
		const reader = response.body!.getReader();
		const decoder = new TextDecoder();
		let buffer = '';

		try {
			while (true) {
				const { done, value } = await reader.read();
				if (done) break;

				buffer += decoder.decode(value, { stream: true });

				// Split on newlines, process complete SSE lines
				const lines = buffer.split('\n');
				buffer = lines.pop() ?? ''; // keep incomplete line in buffer

				for (const line of lines) {
					const trimmed = line.trim();
					if (!trimmed || trimmed.startsWith(':')) continue; // skip empty / comments

					if (trimmed === 'data: [DONE]') return;

					if (trimmed.startsWith('data: ')) {
						const jsonStr = trimmed.slice(6);
						try {
							const parsed = JSON.parse(jsonStr);
							const delta = parsed.choices?.[0]?.delta?.content;
							if (delta) yield delta;
						} catch {
							// Malformed JSON chunk — skip silently (stream continues)
						}
					}
				}
			}
		} finally {
			reader.releaseLock();
		}
	}
}

/**
 * Decompose service — orchestrates LLM-based milestone decomposition.
 *
 * 1. Reads the milestone's source markdown
 * 2. Sends it to the LLM with a structured system prompt
 * 3. Incrementally parses the streaming JSON array response
 * 4. Validates each module with Zod as it becomes available
 * 5. Yields SSE events (module / error / done)
 *
 * No data is written to the database — that's S03's responsibility.
 */

import { LlmClient } from './llm-client.js';
import {
	decomposeModuleSchema,
	type DecomposeModule,
	type DecomposeEvent,
	type DecomposeModuleEvent,
	type DecomposeErrorEvent,
	type DecomposeDoneEvent
} from '$lib/schemas/decompose.js';

// ── System prompt ────────────────────────────────────────────────────────────

const SYSTEM_PROMPT = `你是一个专业的项目管理助手。你的任务是将需求文档拆解为结构化的模块和任务。

## 输出格式

你必须且只能输出一个 JSON 数组，不要包含任何其他文本、注释或 markdown 标记。

\`\`\`json
[
  {
    "name": "模块名称",
    "description": "模块的简要描述",
    "tasks": [
      {
        "title": "任务标题",
        "description": "任务的详细描述（可选）"
      }
    ]
  }
]
\`\`\`

## 拆解原则

1. 每个模块应该是内聚的、可独立开发和交付的功能单元
2. 每个任务应该是明确的、可验证的工作项
3. 模块之间应该有清晰的边界和最小依赖
4. 任务粒度适中：太大需要再拆分，太小则合并
5. 保持模块名称简洁（2-10 个字），描述清晰
6. 任务标题应该是动作导向的（如"实现XX功能"而非"XX功能"）
7. 按照逻辑依赖顺序排列模块

## 注意事项

- 只输出 JSON 数组，不要输出其他任何内容
- 如果需求文档不清晰，根据上下文做出合理推断
- 每个模块至少包含一个任务
- 确保所有任务合起来能覆盖需求文档的全部内容`;

// ── Incremental JSON object extractor ───────────────────────────────────────

/**
 * Tracks brace depth, string state, and escape state to extract
 * complete JSON objects from a streaming byte buffer.
 *
 * Handles:
 * - Nested objects and arrays
 * - Strings containing braces and brackets
 * - Escaped characters inside strings
 * - Multiple complete objects in one chunk
 * - Objects split across chunks
 */
export function extractCompleteJsonObjects(buffer: string): {
	objects: string[];
	remaining: string;
} {
	const objects: string[] = [];
	let depth = 0;
	let inString = false;
	let escaped = false;
	let objStart = -1;

	for (let i = 0; i < buffer.length; i++) {
		const ch = buffer[i];

		if (escaped) {
			escaped = false;
			continue;
		}

		if (ch === '\\' && inString) {
			escaped = true;
			continue;
		}

		if (ch === '"') {
			inString = !inString;
			continue;
		}

		if (inString) continue;

		if (ch === '{' || ch === '[') {
			if (depth === 0) {
				objStart = i;
			}
			depth++;
		} else if (ch === '}' || ch === ']') {
			depth--;
			if (depth === 0 && objStart !== -1) {
				objects.push(buffer.slice(objStart, i + 1));
				objStart = -1;
			}
		}
	}

	return {
		objects,
		remaining: objStart !== -1 ? buffer.slice(objStart) : ''
	};
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Stream-decompose a milestone's source markdown into modules via LLM.
 *
 * @param sourceMd - The raw markdown content of the milestone
 * @param client   - Optional LlmClient instance (for testing / custom config)
 *
 * Yields `DecomposeEvent` objects:
 * - `{ type: 'module', index, module }` — successfully validated module
 * - `{ type: 'error', stage, message }` — error during the process
 * - `{ type: 'done', total, errors }` — stream complete
 */
export async function* streamDecompose(
	sourceMd: string,
	client?: LlmClient
): AsyncGenerator<DecomposeEvent> {
	const llm = client ?? new LlmClient();
	let moduleIndex = 0;
	let errorCount = 0;
	let jsonBuffer = '';

	const userMessage = `请将以下需求文档拆解为模块和任务：\n\n${sourceMd}`;

	try {
		// Phase 1: Connecting
		for await (const chunk of llm.chatCompletionStream(SYSTEM_PROMPT, userMessage)) {
			jsonBuffer += chunk;

			// Try to extract complete objects from the buffer
			const { objects, remaining } = extractCompleteJsonObjects(jsonBuffer);
			jsonBuffer = remaining;

			for (const jsonStr of objects) {
				// The extracted JSON might be an array (the LLM wraps modules in [])
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch {
					// JSON parse failed — might be an array with some bad elements.
					// Strip outer array brackets and re-extract individual objects.
					let innerStr = jsonStr.trim();
					if (innerStr.startsWith('[') && innerStr.endsWith(']')) {
						innerStr = innerStr.slice(1, -1);
					}
					const inner = extractCompleteJsonObjects(innerStr);
					if (inner.objects.length > 0) {
						const parsed: unknown[] = [];
						for (const s of inner.objects) {
							try { parsed.push(JSON.parse(s)); } catch {
								errorCount++;
								yield { type: 'error', stage: 'parsing' as const, message: `JSON parse error: malformed object` };
							}
						}
						candidates = parsed;
						if (candidates.length === 0) continue;
					} else {
						// Truly unparseable
						errorCount++;
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `JSON parse error: unparseable content`
						};
						yield event;
						console.info('[decompose-service] JSON parse error: unparseable content');
						continue;
					}
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);

					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
						console.info('[decompose-service] Zod validation failed for module:', detail);
					}
				}
			}
		}

		// Phase 2: Handle any remaining buffer (partial object at end of stream)
		if (jsonBuffer.trim()) {
			// Try wrapping in array brackets if it looks like the LLM forgot them
			let finalBuffer = jsonBuffer.trim();
			if (!finalBuffer.startsWith('[') && !finalBuffer.startsWith('{')) {
				finalBuffer = `[${finalBuffer}]`;
			}

			const { objects } = extractCompleteJsonObjects(finalBuffer);
			for (const jsonStr of objects) {
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch (parseErr: any) {
					errorCount++;
					const event: DecomposeErrorEvent = {
						type: 'error',
						stage: 'parsing',
						message: `JSON parse error on remaining buffer: ${parseErr.message}`
					};
					yield event;
					continue;
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);
					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
					}
				}
			}
		}
	} catch (err: any) {
		errorCount++;
		// Classify the error stage
		let stage: 'connecting' | 'streaming' | 'parsing' = 'connecting';
		if (moduleIndex > 0) {
			stage = 'streaming';
		}
		const event: DecomposeErrorEvent = {
			type: 'error',
			stage,
			message: err.message
		};
		yield event;
		console.info('[decompose-service] Stream error:', err.message);
	} finally {
		const doneEvent: DecomposeDoneEvent = {
			type: 'done',
			total: moduleIndex,
			errors: errorCount
		};
		yield doneEvent;
		console.info('[decompose-service] Stream complete:', { total: moduleIndex, errors: errorCount });
	}
}

/**
 * POST /api/milestones/:id/decompose
 *
 * Thin SSE wrapper around streamDecompose().
 * Validates preconditions (exists, has sourceMd, status=draft),
 * then streams DecomposeEvents as standard SSE.
 */

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';
import { streamDecompose } from '$lib/server/decompose-service.js';
import type { DecomposeEvent } from '$lib/schemas/decompose.js';

// ── SSE formatting helpers ──────────────────────────────────────────────────

function formatSSE(event: DecomposeEvent): string {
	return `event: ${event.type}\ndata: ${JSON.stringify(event)}\n\n`;
}

// ── Handler ──────────────────────────────────────────────────────────────────

export const POST: RequestHandler = async ({ params }) => {
	const milestone = await getMilestone(db, params.id);

	// 404 — milestone not found
	if (!milestone) {
		return json(
			{ error: 'not_found', message: `Milestone ${params.id} not found` },
			{ status: 404 }
		);
	}

	// 400 — no source markdown to decompose
	if (!milestone.sourceMd) {
		return json(
			{ error: 'bad_request', message: 'Milestone has no source markdown to decompose' },
			{ status: 400 }
		);
	}

	// 400 — only draft milestones can be decomposed
	if (milestone.status !== 'draft') {
		return json(
			{ error: 'bad_request', message: `Milestone status is '${milestone.status}', expected 'draft'` },
			{ status: 400 }
		);
	}

	// Stream SSE events from the decompose service
	const generator = streamDecompose(milestone.sourceMd);

	const stream = new ReadableStream({
		async start(controller) {
			const encoder = new TextEncoder();
			try {
				for await (const event of generator) {
					controller.enqueue(encoder.encode(formatSSE(event)));
				}
				controller.close();
			} catch (err: any) {
				// If the controller is still open, send an error event and close
				try {
					const errorEvent: DecomposeEvent = {
						type: 'error',
						stage: 'streaming',
						message: err.message
					};
					controller.enqueue(encoder.encode(formatSSE(errorEvent)));
					controller.close();
				} catch {
					// Controller already closed — nothing to do
				}
			}
		}
	});

	return new Response(stream, {
		headers: {
			'Content-Type': 'text/event-stream',
			'Cache-Control': 'no-cache',
			'Connection': 'keep-alive'
		}
	});
};

